{"content":"1765: static AbortReason IonCompile(JSContext* cx, HandleScript script,
1766:                               jsbytecode* osrPc) {
1767:   cx->check(script);
1768: 
1769:   if (!cx->zone()->ensureJitZoneExists(cx)) {
1770:     return AbortReason::Error;
1771:   }
1772: 
1773:   UniquePtr<LifoAlloc> alloc =
1774:       cx->runtime()->jitRuntime()->tryReuseIonLifoAlloc();
1775:   if (!alloc) {
1776:     alloc = cx->make_unique<LifoAlloc>(TempAllocator::PreferredLifoChunkSize,
1777:                                        js::MallocArena);
1778:     if (!alloc) {
1779:       return AbortReason::Error;
1780:     }
1781:   }
1782: 
1783:   TempAllocator* temp = alloc->new_<TempAllocator>(alloc.get());
1784:   if (!temp) {
1785:     return AbortReason::Alloc;
1786:   }
1787: 
1788:   MIRGraph* graph = alloc->new_<MIRGraph>(temp);
1789:   if (!graph) {
1790:     return AbortReason::Alloc;
1791:   }
1792: 
1793:   InlineScriptTree* inlineScriptTree =
1794:       InlineScriptTree::New(temp, nullptr, nullptr, script);
1795:   if (!inlineScriptTree) {
1796:     return AbortReason::Alloc;
1797:   }
1798: 
1799:   CompileInfo* info =
1800:       alloc->new_<CompileInfo>(CompileRuntime::get(cx->runtime()), script,
1801:                                osrPc, script->needsArgsObj(), inlineScriptTree);
1802:   if (!info) {
1803:     return AbortReason::Alloc;
1804:   }
1805: 
1806:   const OptimizationInfo* optimizationInfo =
1807:       IonOptimizations.get(OptimizationLevel::Normal);
1808:   const JitCompileOptions options(cx);
1809: 
1810:   MIRGenerator* mirGen =
1811:       alloc->new_<MIRGenerator>(CompileRealm::get(cx->realm()), options, temp,
1812:                                 graph, info, optimizationInfo);
1813:   if (!mirGen) {
1814:     return AbortReason::Alloc;
1815:   }
1816: 
1817:   auto clearDependencies =
1818:       mozilla::MakeScopeExit([mirGen]() { mirGen->cleanup(); });
1819: 
1820:   MOZ_ASSERT(!script->baselineScript()->hasPendingIonCompileTask());
1821:   MOZ_ASSERT(!script->hasIonScript());
1822:   MOZ_ASSERT(script->canIonCompile());
1823: 
1824:   if (osrPc) {
1825:     script->jitScript()->setHadIonOSR();
1826:   }
1827: 
1828:   AbortReasonOr<WarpSnapshot*> result = CreateWarpSnapshot(cx, mirGen, script);
1829:   if (result.isErr()) {
1830:     return result.unwrapErr();
1831:   }
1832:   WarpSnapshot* snapshot = result.unwrap();
1833: 
1834:   // If possible, compile the script off thread.
1835:   if (options.offThreadCompilationAvailable()) {
1836:     JitSpew(JitSpew_IonSyncLogs,
1837:             "Can't log script %s:%u:%u"
1838:             ". (Compiled on background thread.)",
1839:             script->filename(), script->lineno(),
1840:             script->column().oneOriginValue());
1841: 
1842:     IonCompileTask* task = alloc->new_<IonCompileTask>(cx, *mirGen, snapshot);
1843:     if (!task) {
1844:       return AbortReason::Alloc;
1845:     }
1846: 
1847:     AutoLockHelperThreadState lock;
1848:     if (!StartOffThreadIonCompile(task, lock)) {
1849:       JitSpew(JitSpew_IonAbort, "Unable to start off-thread ion compilation.");
1850:       mirGen->spewEndFunction();
